-- Tour 1: Phong Nha - Kẻ Bàng
(1, 3, 5, 'Tour tuyệt vời! Hướng dẫn viên rất nhiệt tình và am hiểu về văn hóa địa phương. Điểm nổi bật nhất là zipline qua sông Chày, trải nghiệm không thể nào quên. Ẩm thực ngon, khách sạn sạch sẽ. Rất recommend!', '2026-05-03 14:00:00'),
(1, 5, 4, 'Tour khá hay, nhưng thời gian hơi gấp. Động Phong Nha rất đẹp, nên ở lại lâu hơn một chút. Nhìn chung vẫn rất hài lòng và sẽ giới thiệu cho bạn bè.', '2026-05-06 16:30:00'),
(1, 4, 5, 'Chuyến đi quá ấn tượng! Hang động kỳ lạ, zipline siêu hay. Thực đơn có nhiều món ngon đặc sản miền Trung. Khách sạn sạch sẽ, dịch vụ tốt. Sẽ quay lại!', '2026-05-04 11:00:00'),
(1, 6, 5, 'Điểm đến tuyệt vời cho những người thích khám phá thiên nhiên. Zipline, chèo thuyền kayak, tắm bùn đều rất thú vị. Hướng dẫn viên Minh rất am hiểu và vui tính. Cảm ơn rất nhiều!', '2026-05-07 13:00:00'),
(1, 7, 4, 'Tour khá, nhưng có điểm cần cải thiện: bữa ăn có thể ngon hơn, xe hơi cũ. Tuy nhiên, trải nghiệm khám phá hang động và zipline rất hay, nên hãy thử!', '2026-05-08 15:30:00'),
(1, 9, 5, 'Tuyệt vời! Động Phong Nha quá đẹp, zipline cực hay. Thực đơn có cháo canh và bánh bột lọc siêu ngon. Khách sạn sạch sẽ, nhân viên thân thiện. Rất recommend!', '2026-05-09 17:00:00'),
(1, 10, 5, 'Tôi và bạn bè rất thích tour này! Zipline là điểm nổi bật nhất, trải nghiệm mạo hiểm đầy cảm giác. Hướng dẫn viên An rất vui tính và chuyên nghiệp. Ẩm thực ngon, khách sạn tiện nghi.', '2026-05-10 14:00:00'),
(1, 11, 4, 'Tour hay, nhưng thời gian di chuyển hơi nhiều. Tuy nhiên, các hoạt động khám phá rất thú vị. Động Phong Nha đẹp tuyệt, nên chụp nhiều ảnh. Nhìn chung vẫn rất hài lòng!', '2026-05-11 12:00:00'),
(1, 12, 5, 'Chuyến đi hoàn hảo! Từ zipline đến chèo thuyền kayak, mọi thứ đều quá hay. Hướng dẫn viên Hương rất nhiệt tình và am hiểu. Khách sạn có view đẹp, bữa ăn ngon. Rất cảm ơn!', '2026-05-12 18:00:00'),
(1, 13, 5, 'Rất hài lòng! Động Phong Nha là kỳ quan thiên nhiên, zipline qua sông Chày quá hay. Thực đơn có nhiều món ngon đặc sản. Khách sạn sạch sẽ, dịch vụ tốt. Sẽ giới thiệu cho bạn bè!', '2026-05-13 10:00:00'),
-- Tour 2: Hà Nội - Hạ Long - Sapa
(2, 6, 5, 'Chuyến đi hoàn hảo! Tàu du lịch Hạ Long quá đẹp, đồ ăn ngon, dịch vụ tốt. Sapa mờ sương như trong mơ, ruộng bậc thang tuyệt đẹp. Hướng dẫn viên An rất vui tính và chuyên nghiệp.', '2026-05-05 10:00:00'),
(2, 7, 5, 'Tôi và gia đình rất thích tour này! Đứa trẻ thích nhất là tàu du lịch và chèo thuyền kayak. Hướng dẫn viên rất kiên nhẫn với trẻ em. Món ăn ngon, khách sạn tiện nghi. Sẽ quay lại!', '2026-05-07 11:30:00'),
(2, 3, 5, 'Chuyến đi ấn tượng! Tàu du lịch Hạ Long quá đẹp, đồ ăn ngon. Sapa mờ sương như cổ tích, ruộng bậc thang tuyệt đẹp. Hướng dẫn viên Minh rất am hiểu và vui tính.', '2026-05-06 14:00:00'),
(2, 4, 4, 'Tour khá hay, nhưng thời gian hơi gấp. Tàu du lịch Hạ Long đẹp, nhưng phòng hơi nhỏ. Sapa quá đẹp, nên ở lại lâu hơn. Nhìn chung vẫn rất hài lòng!', '2026-05-08 16:00:00'),
(2, 5, 5, 'Tuyệt vời! Fansipan quá đẹp, tàu du lịch Hạ Long siêu sang. Thực đơn có phở Hà Nội và bún chả ngon tuyệt. Khách sạn sạch sẽ, nhân viên thân thiện.', '2026-05-09 13:00:00'),
(2, 9, 5, 'Tôi và bạn bè rất thích tour này! Tàu du lịch Hạ Long là điểm nổi bật nhất, phòng đẹp, đồ ăn ngon. Hướng dẫn viên Hương rất nhiệt tình và chuyên nghiệp.', '2026-05-10 15:30:00'),
(2, 10, 4, 'Tour hay, nhưng đi tàu hơi mệt. Tuy nhiên, cảnh đẹp Sapa và Hạ Long quá tuyệt, nên chụp nhiều ảnh. Hướng dẫn viên An rất vui tính và kiên nhẫn.', '2026-05-11 18:00:00'),
(2, 11, 5, 'Chuyến đi hoàn hảo! Từ Hạ Long đến Sapa, mọi thứ đều quá hay. Tàu du lịch 5 sao, khách sạn tiện nghi. Hướng dẫn viên Minh am hiểu văn hóa địa phương rất tốt.', '2026-05-12 11:00:00'),
(2, 12, 5, 'Rất hài lòng! Ruộng bậc thang Mường Hoa quá đẹp, tàu du lịch Hạ Long siêu sang. Thực đơn có nhiều món ngon đặc sản miền Bắc. Khách sạn sạch sẽ, dịch vụ tốt.', '2026-05-13 17:00:00'),
(2, 13, 5, 'Chuyến đi quá ấn tượng! Fansipan, Hạ Long, Sapa đều quá đẹp. Hướng dẫn viên Hương rất nhiệt tình và chuyên nghiệp. Sẽ giới thiệu cho bạn bè và quay lại!', '2026-05-14 12:00:00'),
-- Tour 3: TP.HCM - Mỹ Tho - Cần Thơ
(3, 9, 5, 'Miền Tây thật tuyệt! Chợ nổi Cái Răng là trải nghiệm không thể bỏ lỡ. Người dân thân thiện, ẩm thực ngon ngọt. Xuồng ba lá rất thú vị, nên thử trải nghiệm. Rất hài lòng!', '2026-05-05 18:00:00'),
(3, 10, 4, 'Tour khá hay, nhưng trời quá nóng. Vườn trái cây Mỹ Tho có nhiều trái cây ngon, nên mua nhiều về làm quà. Chợ nổi Cái Răng rất sôi động, nhưng hơi đông người. Nhìn chung vẫn hay.', '2026-05-08 09:00:00'),
(3, 3, 5, 'Chuyến đi thú vị! Chợ nổi Cái Răng quá đặc trưng, xuồng ba lá hay. Vườn trái cây có nhiều loại trái cây ngon. Ẩm thực miền Tây ngon tuyệt, bánh xèo và canh chua quá hay!', '2026-05-06 13:00:00'),
(3, 4, 5, 'Tôi và gia đình rất thích! Chợ nổi Cái Răng là trải nghiệm độc đáo, con tôi thích nhất là xuồng ba lá. Hướng dẫn viên An rất vui tính và kiên nhẫn. Khách sạn sạch sẽ, tiện nghi.', '2026-05-07 15:00:00'),
(3, 5, 4, 'Tour hay, nhưng thời gian di chuyển hơi nhiều. Tuy nhiên, các điểm đến rất thú vị. Vườn trái cây Mỹ Tho có nhiều trái cây ngon, nên thử. Chợ nổi Cái Răng quá đặc trưng!', '2026-05-09 11:00:00'),
(3, 6, 5, 'Tuyệt vời! Miền Tây quá yên bình, chợ nổi Cái Răng quá hay. Thực đơn có nhiều món ngon đặc sản: bánh xèo, canh chua, hủ tiếu. Khách sạn có view sông đẹp, nhân viên thân thiện.', '2026-05-10 17:00:00'),
(3, 7, 5, 'Chuyến đi hoàn hảo! Từ Mỹ Tho đến Cần Thơ, mọi thứ đều quá hay. Xuồng ba lá, chợ nổi, vườn trái cây đều thú vị. Hướng dẫn viên Minh am hiểu văn hóa miền Tây rất tốt.', '2026-05-11 14:00:00'),
(3, 11, 4, 'Tour khá, nhưng có điểm cần cải thiện: xe hơi cũ, bữa ăn có thể ngon hơn. Tuy nhiên, trải nghiệm khám phá chợ nổi và vườn trái cây rất thú vị.', '2026-05-12 10:00:00'),
(3, 12, 5, 'Rất hài lòng! Miền Tây quá đẹp, chợ nổi Cái Răng quá đặc trưng. Thực đơn có nhiều món ngon, khách sạn sạch sẽ. Hướng dẫn viên Hương rất nhiệt tình. Sẽ quay lại!', '2026-05-13 16:00:00'),
(3, 13, 5, 'Chuyến đi quá ấn tượng! Xuồng ba lá, chợ nổi, vườn trái cây đều thú vị. Ẩm thực miền Tây ngon tuyệt. Hướng dẫn viên An rất vui tính. Rất recommend!', '2026-05-14 12:00:00'),
-- Tour 4: Nha Trang - Vinpearl
(4, 11, 5, 'Vinpearl Land quá hay! Con tôi thích nhất là các trò chơi cảm giác mạnh. Resort đẹp, view biển tuyệt đẹp. Thủy cung có nhiều loài thủy sinh, rất thú vị cho trẻ em. Ăn uống ngon, dịch vụ tốt.', '2026-05-05 20:00:00'),
(4, 12, 5, 'Tour honeymoon hoàn hảo! Resort Vinpearl quá đẹp, phòng được trang trí hoa và nến rất lãng mạn. Ăn tối trên biển rất lãng mạn. Cáp treo vượt biển là trải nghiệm độc đáo. Rất cảm ơn!', '2026-05-09 12:00:00'),
(4, 3, 5, 'Vinpearl Land quá hay! Resort đẹp, view biển tuyệt đẹp. Thủy cung có nhiều loài thủy sinh, trò chơi giải trí hay. Ẩm thực ngon, dịch vụ tốt. Sẽ quay lại!', '2026-05-06 15:00:00'),
(4, 4, 5, 'Tôi và gia đình rất thích! Vinpearl Land có nhiều trò chơi cho trẻ em, thủy cung quá hay. Resort đẹp, view biển tuyệt đẹp. Hướng dẫn viên An rất nhiệt tình.', '2026-05-07 17:00:00'),
(4, 5, 4, 'Tour hay, nhưng Vinpearl Land hơi đông người. Tuy nhiên, resort đẹp, view biển tuyệt đẹp. Thủy cung có nhiều loài thủy sinh, rất thú vị. Ẩm thực ngon, dịch vụ tốt.', '2026-05-08 13:00:00'),
(4, 6, 5, 'Tuyệt vời! Cáp treo vượt biển quá hay, resort Vinpearl quá đẹp. Thủy cung có nhiều loài thủy sinh, trò chơi giải trí hay. Ẩm thực có nhiều món hải sản ngon. Khách sạn sạch sẽ.', '2026-05-10 11:00:00'),
(4, 7, 5, 'Chuyến đi hoàn hảo! Vinpearl Land, thủy cung, cáp treo đều quá hay. Resort đẹp, view biển tuyệt đẹp. Hướng dẫn viên Minh am hiểu rất tốt. Ẩm thực ngon.', '2026-05-11 18:00:00'),
(4, 9, 4, 'Tour khá, nhưng có điểm cần cải thiện: vé vào Vinpearl Land hơi đắt, ăn uống trong công viên cũng đắt. Tuy nhiên, trải nghiệm vẫn rất thú vị.', '2026-05-12 14:00:00'),
(4, 10, 5, 'Rất hài lòng! Vinpearl Land quá hay, thủy cung có nhiều loài thủy sinh. Resort đẹp, view biển tuyệt đẹp. Hướng dẫn viên Hương rất nhiệt tình. Sẽ giới thiệu cho bạn bè!', '2026-05-13 10:00:00'),
(4, 13, 5, 'Chuyến đi quá ấn tượng! Cáp treo vượt biển, Vinpearl Land, thủy cung đều quá hay. Ẩm thực có nhiều món hải sản ngon. Resort đẹp, dịch vụ tốt. Rất recommend!', '2026-05-14 16:00:00'),
-- Tour 5: Sapa - Fansipan
(5, 13, 5, 'Fansipan quá tuyệt! Cáp treo rất hiện đại, cảnh đẹp từ trên cao không thể tả. Thị trấn Sapa mờ sương như cổ tích. Người dân H''Mông thân thiện, văn hóa độc đáo. Thực đơn có nhiều món ngon đặc sản. Rất recommend!', '2026-05-04 15:00:00'),
(5, 15, 4, 'Tour hay, nhưng đi tàu hơi mệt. Cáp treo Fansipan quá hay, nên đi sớm để không phải xếp hàng. Ruộng bậc thang Mường Hoa rất đẹp, nên chụp nhiều ảnh. Nhìn chung vẫn rất hài lòng.', '2026-05-08 17:00:00'),
(5, 3, 5, 'Fansipan quá tuyệt! Cáp treo hiện đại, cảnh đẹp từ trên cao không thể tả. Thị trấn Sapa mờ sương như cổ tích. Ruộng bậc thang Mường Hoa quá đẹp. Ẩm thực có thịt trâu gác bếp ngon tuyệt!', '2026-05-05 11:00:00'),
(5, 4, 5, 'Tôi và bạn bè rất thích! Fansipan quá đẹp, cáp treo hay. Thị trấn Sapa mờ sương như cổ tích, người dân H''Mông thân thiện. Hướng dẫn viên An rất vui tính.', '2026-05-06 13:00:00'),
(5, 5, 4, 'Tour hay, nhưng thời tiết Sapa hơi lạnh. Tuy nhiên, Fansipan quá đẹp, cáp treo hay. Ruộng bậc thang Mường Hoa quá đẹp, nên chụp nhiều ảnh. Khách sạn có view núi đẹp.', '2026-05-07 15:00:00'),
(5, 6, 5, 'Tuyệt vời! Fansipan, cáp treo, ruộng bậc thang Mường Hoa đều quá hay. Thị trấn Sapa mờ sương như cổ tích. Ẩm thực có nhiều món ngon đặc sản. Khách sạn sạch sẽ.', '2026-05-09 18:00:00'),
(5, 7, 5, 'Chuyến đi hoàn hảo! Từ Fansipan đến bản Mường Hoa, mọi thứ đều quá hay. Hướng dẫn viên Minh am hiểu văn hóa dân tộc rất tốt. Thực đơn có thịt trâu gác bếp ngon tuyệt.', '2026-05-10 12:00:00'),
(5, 9, 4, 'Tour khá, nhưng đi tàu hơi mệt và thời gian hơi gấp. Tuy nhiên, Fansipan quá đẹp, cáp treo hay. Ruộng bậc thang Mường Hoa quá đẹp. Nhìn chung vẫn hay.', '2026-05-11 14:00:00'),
(5, 10, 5, 'Rất hài lòng! Fansipan, cáp treo, ruộng bậc thang Mường Hoa đều quá hay. Thị trấn Sapa mờ sương như cổ tích. Hướng dẫn viên Hương rất nhiệt tình. Sẽ quay lại!', '2026-05-12 17:00:00'),
(5, 11, 5, 'Chuyến đi quá ấn tượng! Fansipan quá đẹp, cáp treo hiện đại. Thị trấn Sapa mờ sương như cổ tích. Ẩm thực có nhiều món ngon đặc sản. Hướng dẫn viên An rất vui tính. Rất recommend!', '2026-05-13 11:00:00');
