('Tour Ấm Áp', 'tour-am-ap', 'Chuyến đi dành cho người cao tuổi với lịch trình nhẹ nhàng', 'active', '2026-04-30 09:00:00');
INSERT INTO TOURS (category_id, name, slug, description, status, price_adult, price_child, images, created_at) VALUES
(1, 'Hà Nội - Hạ Long - Sapa 4N3Đ', 'ha-noi-ha-long-sapa-4n3d', '<h3>Giới thiệu tour</h3><p>Tour du lịch Hà Nội - Hạ Long - Sapa 4 ngày 3 đêm là hành trình khám phá miền Bắc Việt Nam hoàn hảo, kết hợp văn hóa cổ điển của thủ đô, kỳ quan thiên nhiên Vịnh Hạ Long và cảnh đẹp núi rừng Sapa.</p><h3>Điểm nổi bật</h3><ul><li>Khám phá Lăng Bác, Chùa Một Cột - biểu tượng thủ đô Hà Nội</li><li>Vịnh Hạ Long - kỳ quan thiên nhiên thế giới với hàng ngàn hòn đảo kỳ lạ</li><li>Sapa mờ sương với ruộng bậc thang tuyệt đẹp và văn hóa dân tộc đa dạng</li><li>Thưởng thức ẩm thực đặc sắc miền Bắc: phở, chả cá, bún chả</li><li>Hướng dẫn viên nhiệt tình, kinh nghiệm và am hiểu văn hóa</li></ul><h3>Ngày 1: <strong>Hà Nội City Tour</strong></h3><ul><li>Sáng (08:00): Đón khách tại sân bay Nội Bài, về khách sạn nhận phòng, nghỉ ngơi</li><li>Trưa (12:00): Ăn trưa tại nhà hàng địa phương với phở Hà Nội và các món ăn đặc trưng</li><li>Chiều (14:00): Tham quan Lăng Bác, Chùa Một Cột, Văn Miếu - Quốc Tử Giám</li><li>Tối (18:00): Ăn tối, đi dạo quanh Hồ Gươm, ngắm đêm thành phố</li></ul><h3>Ngày 2: <strong>Hà Nội - Hạ Long</strong></h3><ul><li>Sáng (07:30): Đi Hạ Long bằng xe limousine, check-in tàu du lịch 5 sao</li><li>Trưa (12:00): Ăn trưa trên tàu với hải sản tươi ngon</li><li>Chiều (14:00): Khám phá hang động Sửng Sốt, chèo thuyền kayak giữa vịnh</li><li>Tối (19:00): Thưởng thức bữa tối trên tàu, ngắm đêm Hạ Long lung linh</li></ul><h3>Ngày 3: <strong>Hạ Long - Sapa</strong></h3><ul><li>Sáng (06:00): Tắm biển Titop, chụp ảnh toàn cảnh vịnh, trả tàu về bến</li><li>Trưa (11:00): Ăn trưa, đi xe về Lào Cai, lên tàu ngủ đêm đến Sapa</li><li>Chiều (16:00): Check-in khách sạn Sapa, tham quan bản Cat Cat, gặp gỡ người H'Mông</li><li>Tối (19:00): Ăn tối với đặc sản thit lợn cắp nách, nghỉ đêm tại Sapa</li></ul><h3>Ngày 4: <strong>Sapa - Hà Nội</strong></h3><ul><li>Sáng (06:30): Ngắm bình minh tại Fansipan, đi cáp treo lên đỉnh núi "Nóc nhà Đông Dương"</li><li>Trưa (12:00): Ăn trưa, đi xe về Hà Nội qua tuyến đường đèo đẹp</li><li>Chiều (17:00): Mua sắm đặc sản, đưa khách ra sân bay hoặc khách sạn</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đời mới limousine đưa đón theo lịch trình</li><li>Khách sạn 3-4 sao (2 người/phòng)</li><li>Tàu du lịch 5 sao Hạ Long (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Vé cáp treo Fansipan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li><li>Nước uống trên xe</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe (không bắt buộc)</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp cho Sapa, nhẹ nhàng cho Hạ Long</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết Sapa lạnh về ban đêm, nên chuẩn bị áo ấm</li><li>Tuân thủ quy định trên tàu du lịch</li></ul>', 'active', 5500000, 3800000, '["https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2026-01-15 10:00:00'),
(2, 'Phong Nha - Kẻ Bàng 2N1Đ', 'phong-nha-ke-bang-2n1d', '<h3>Giới thiệu tour</h3><p>Tour du lịch Khám phá Phong Nha - Kẻ Bàng 2 ngày 1 đêm sẽ đưa quý khách đến với Vườn quốc gia Phong Nha - Kẻ Bàng, Di sản thiên nhiên thế giới với hệ thống hang động kỳ vĩ nhất thế giới. Đây là hành trình khám phá thiên nhiên hoang dã, trải nghiệm các hoạt động mạo hiểm đầy thú vị như zipline, chèo thuyền kayak, tắm bùn thiên nhiên.</p><h3>Điểm nổi bật</h3><ul><li>Zipline 400m qua thung lũng sông Chày - trải nghiệm mạo hiểm đầy cảm giác</li><li>Chèo thuyền kayak khám phá Hang Tối - hang động hoang sơ chưa có đèn điện</li><li>Tắm bùn thiên nhiên tại suối Moọc - liệu pháp làm đẹp độc đáo</li><li>Động Phong Nha - Di sản thiên nhiên thế giới với hệ thống hang động kỳ vĩ</li><li>Sông Chày - dòng sông xanh ngọc chảy qua thung lũng đá vôi</li><li>Trải nghiệm thiên nhiên hoang dã tại Vườn quốc gia Phong Nha - Kẻ Bàng</li><li>Bãi biển Bảo Ninh - bãi biển hoang sơ còn nguyên vẹn nét đẹp tự nhiên</li></ul><h3>Ngày 1: <strong>Đồng Hới - Phong Nha - Sông Chày</strong></h3><ul><li>Sáng (08:00): Đón khách tại sân bay/ga Đồng Hới, khởi hành đi Phong Nha</li><li>Trưa (11:30): Ăn trưa tại nhà hàng địa phương với đặc sản: cháo canh, bánh bột lọc, khoai lang mật</li><li>Chiều (14:00): Tham quan động Phong Nha bằng thuyền - ngắm nhũ đá kỳ ảo, khám phá hang Ký, hang Cô Tiên</li><li>Tối (17:00): Check-in khách sạn Phong Nha, ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Sông Chày - Hang Tối - Zipline - Đồng Hới</strong></h3><ul><li>Sáng (07:30): Ăn sáng, di chuyển đi sông Chày</li><li>Trưa (09:00): Trải nghiệm zipline 400m qua thung lũng sông Chày, tắm bùn thiên nhiên tại suối Moọc</li><li>Chiều (11:00): Ăn trưa picnic, chèo thuyền kayak khám phá Hang Tối hoang sơ</li><li>Tối (15:00): Trở về Đồng Hới, tham quan bãi biển Bảo Ninh, ăn tối hải sản, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón sân bay/ga Đồng Hới - Phong Nha - Đồng Hới</li><li>Khách sạn 2-3 sao tại Phong Nha (1 đêm, 2 người/phòng)</li><li>Vé tham quan: động Phong Nha (bao gồm thuyền), sông Chày</li><li>Thiết bị zipline đạt chuẩn an toàn</li><li>Thuyền kayak, đèn pin đội đầu, áo phao khám phá Hang Tối</li><li>Bùn tắm thiên nhiên tại suối Moọc</li><li>Bữa ăn đầy đủ: 1 bữa sáng, 2 bữa trưa, 1 bữa tối</li><li>Hướng dẫn viên địa phương am hiểu về hang động</li><li>Bảo hiểm du lịch mạo hiểm</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe (không bắt buộc)</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: quần áo nhẹ, thoáng mát, giày thể thao đế bám tốt</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết mùa hè nóng ẩm, nên mang theo áo mưa nhẹ</li><li>Tuân thủ hướng dẫn an toàn của HDV khi tham gia hoạt động mạo hiểm</li><li>Không mang vali lớn khi vào hang động, chỉ mang balo nhỏ</li><li>Giữ gìn vệ sinh môi trường, không xả rác bừa bãi</li><li>Trẻ em dưới 6 tuổi và người cao tuổi trên 70 tuổi không nên tham gia zipline</li></ul>', 'active', 2800000, 2000000, '["https://images.unsplash.com/photo-1583306346313-e9295d87f9eb?w=800&q=80","https://images.unsplash.com/photo-1533050487297-09b450131914?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-01-20 14:00:00'),
(3, 'TP.HCM - Mỹ Tho - Cần Thơ 3N2Đ', 'tphcm-mytho-cantho-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Tây Nam Bộ 3 ngày 2 đêm sẽ đưa quý khách trải nghiệm văn hóa sông nước miệt vườn, tham quan các điểm đến nổi tiếng như Mỹ Tho, Cần Thơ, Bến Tre, hòa mình vào không khí yên bình của miền Tây.</p><h3>Điểm nổi bật</h3><ul><li>Trải nghiệm sông nước miệt vườn Tây Nam Bộ với cảnh đẹp yên bình</li><li>Tham quan chợ nổi Cái Răng - đặc sản miền Tây độc đáo</li><li>Khám phá vườn trái cây Mỹ Tho với nhiều loại trái cây ngon</li><li>Thưởng thức ẩm thực miền Tây: bánh xèo, hủ tiếu, canh chua cá lóc</li><li>Check-in tại Bến Tre - xứ dừa với cảnh đẹp miệt vườn</li><li>Đi xuồng ba lá khám phá kênh rạch miền Tây</li><li>Gặp gỡ người dân địa phương và tìm hiểu cuộc sống sông nước</li></ul><h3>Ngày 1: <strong>TP.HCM - Mỹ Tho - Bến Tre</strong></h3><ul><li>Sáng (07:30): Đón khách tại TP.HCM, đi xe về Mỹ Tho</li><li>Trưa (11:30): Ăn trưa tại vườn trái cây với các loại trái cây tươi</li><li>Chiều (14:00): Tham quan Bến Tre, đi xuồng ba lá khám phá kênh rạch</li><li>Tối (18:00): Ăn tối đặc sản miền Tây, nghỉ đêm tại Bến Tre</li></ul><h3>Ngày 2: <strong>Bến Tre - Cần Thơ</strong></h3><ul><li>Sáng (07:00): Đi Cần Thơ, tham quan chợ nổi Cái Răng vào buổi sáng sớm</li><li>Trưa (12:00): Ăn trưa tại Cần Thơ với canh chua cá lóc và bánh xèo</li><li>Chiều (14:00): Tham quan vườn cẩm thạch, thăm quan khu bảo tồn thiên nhiên</li><li>Tối (19:00): Ăn tối, nghỉ đêm tại Cần Thơ</li></ul><h3>Ngày 3: <strong>Cần Thơ - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản miền Tây: mứt, rượu trái cây</li><li>Trưa (11:00): Ăn trưa, đi xe về TP.HCM</li><li>Chiều (15:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đời mới đưa đón TP.HCM - Mỹ Tho - Cần Thơ - TP.HCM</li><li>Khách sạn 2-3 sao (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Xe xuồng ba lá khám phá kênh rạch</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li><li>Nước uống trên xe</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm</li><li>Thời tiết miền Tây nóng ẩm, nên chuẩn bị khăn ướt</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường sông nước</li></ul>', 'active', 3500000, 2500000, '["https://images.unsplash.com/photo-1597165309222-d5c746940c78?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80"]', '2026-02-05 11:00:00'),
(4, 'Nha Trang - Vinpearl 4N3Đ', 'nha-trang-vinpearl-4n3d', '<h3>Giới thiệu tour</h3><p>Tour nghỉ dưỡng Nha Trang - Vinpearl 4 ngày 3 đêm là lựa chọn hoàn hảo cho kỳ nghỉ biển, kết hợp thư giãn tại resort cao cấp và vui chơi tại Vinpearl Land - công viên giải trí lớn nhất miền Trung.</p><h3>Điểm nổi bật</h3><ul><li>Vinpearl Land - công viên giải trí lớn nhất miền Trung với nhiều trò chơi hấp dẫn</li><li>Cáp treo vượt biển dài nhất Việt Nam - trải nghiệm độc đáo</li><li>Bãi biển Nha Trang xanh trong, một trong những bãi biển đẹp nhất Việt Nam</li><li>Thủy cung Vinpearl - aquarium khổng lồ với nhiều loài thủy sinh</li><li>Spa và massage thư giãn tại resort Vinpearl</li><li>Resort 5 sao với view biển tuyệt đẹp</li><li>Thưởng thức hải sản tươi ngon tại Nha Trang</li></ul><h3>Ngày 1: <strong>Nha Trang - Vinpearl</strong></h3><ul><li>Sáng (08:00): Đón khách tại sân bay Cam Ranh, về Nha Trang</li><li>Trưa (12:00): Ăn trưa tại nhà hàng hải sản</li><li>Chiều (14:00): Đi cáp treo ra đảo Vinpearl, check-in resort</li><li>Tối (18:00): Ăn tối tại resort, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Vinpearl Land</strong></h3><ul><li>Sáng (08:30): Tham quan Vinpearl Land, chơi các trò chơi giải trí</li><li>Trưa (12:00): Ăn trưa tại khu ăn uống của công viên</li><li>Chiều (14:00): Tham quan thủy cung Vinpearl, bơi biển</li><li>Tối (19:00): Ăn tối, xem biểu diễn âm nhạc, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Nha Trang City Tour</strong></h3><ul><li>Sáng (08:30): Trở về đất liền, tham quan Viện Hải dương học, chợ Đầm</li><li>Trưa (12:00): Ăn trưa đặc sản Nha Trang</li><li>Chiều (14:00): Đi bãi biển, nghỉ ngơi, thư giãn</li><li>Tối (18:00): Ăn tối hải sản, nghỉ đêm</li></ul><h3>Ngày 4: <strong>Nha Trang</strong></h3><ul><li>Sáng (08:30): Mua sắm đặc sản Nha Trang: rượu nếp, mực nướng</li><li>Trưa (12:00): Ăn trưa, đưa khách ra sân bay</li><li>Chiều (14:00): Kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón sân bay Cam Ranh - Nha Trang - Vinpearl</li><li>Resort 5 sao Vinpearl (2 người/phòng)</li><li>Khách sạn 4 sao Nha Trang (2 người/phòng)</li><li>Vé cáp treo khứ hồi Vinpearl</li><li>Vé Vinpearl Land</li><li>Vé thủy cung</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, áo bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết Nha Trang nóng, nên chuẩn bị nước uống đầy đủ</li><li>Tuân thủ quy định an toàn tại công viên giải trí</li><li>Trẻ em cần được người lớn giám sát khi chơi các trò chơi</li></ul>', 'active', 5800000, 4200000, '["https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80"]', '2026-02-10 09:30:00'),
(5, 'Sapa - Fansipan 2N1Đ', 'sapa-fansipan-2n1d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Sapa và chinh phục Fansipan - "Nóc nhà Đông Dương" 2 ngày 1 đêm là hành trình khám phá vẻ đẹp núi rừng và văn hóa dân tộc miền Bắc Việt Nam.</p><h3>Điểm nổi bật</h3><ul><li>Chinh phục đỉnh Fansipan - nóc nhà Đông Dương với độ cao 3.143m</li><li>Tàu hỏa leo núi trải nghiệm độc đáo lên Fansipan</li><li>Ruộng bậc thang Mường Hoa - cảnh đẹp tuyệt đẹp</li><li>Khám phá văn hóa người Dao đỏ, người H'Mông</li><li>Thưởng thức thịt trâu gác bếp - đặc sản Sapa</li><li>Thị trấn Sapa mờ sương với không khí trong lành</li><li>Check-in tại khách sạn với view núi rừng tuyệt đẹp</li></ul><h3>Ngày 1: <strong>Hà Nội - Sapa</strong></h3><ul><li>Sáng (06:00): Đón khách, đi tàu hỏa về Lào Cai</li><li>Trưa (12:00): Ăn trưa trên tàu</li><li>Chiều (16:00): Đến Lào Cai, đi xe về Sapa, check-in khách sạn</li><li>Tối (19:00): Ăn tối với đặc sản Sapa, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Sapa - Fansipan - Hà Nội</strong></h3><ul><li>Sáng (06:00): Ngắm bình minh, đi cáp treo lên Fansipan</li><li>Trưa (12:00): Ăn trưa trên đỉnh núi hoặc tại khách sạn</li><li>Chiều (14:00): Tham quan bản Mường Hoa, đi tàu về Hà Nội</li><li>Tối (20:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé tàu hỏa khứ hồi Hà Nội - Lào Cai</li><li>Xe đưa đón Lào Cai - Sapa - Fansipan</li><li>Vé cáp treo Fansipan</li><li>Khách sạn 2-3 sao Sapa (1 đêm, 2 người/phòng)</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp, đồ len, giày thể thao tốt</li><li>Mang theo: kem chống nắng, mũ, kính râm, máy ảnh</li><li>Thời tiết Sapa rất lạnh về ban đêm, nên chuẩn bị đủ áo ấm</li><li>Tuân thủ hướng dẫn an toàn khi đi cáp treo và tàu hỏa leo núi</li><li>Người có bệnh tim, huyết áp nên tham khảo ý kiến bác sĩ trước khi đi</li></ul>', 'active', 3200000, 2400000, '["https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2026-02-15 10:00:00'),
(6, 'Huế - Đà Nẵng - Hội An 4N3Đ', 'hue-da-nang-hoi-an-4n3d', '<h3>Giới thiệu tour</h3><p>Tour khám phá miền Trung 4 ngày 3 đêm kết hợp di sản văn hóa thế giới Huế, thành phố hiện đại Đà Nẵng và phố cổ Hội An lung linh.</p><h3>Điểm nổi bật</h3><ul><li>Tham quan Đại Nội Huế - di sản văn hóa thế giới</li><li>Biển Mỹ Khê - một trong 6 bãi biển đẹp nhất hành tinh</li><li>Phố cổ Hội An lung linh đèn lồng về buổi tối</li><li>Cầu Rồng - biểu tượng mới của Đà Nẵng</li><li>Thưởng thức đặc sản Cao Lầu, Mì Quảng, bánh mì Hội An</li><li>Tham quan Bà Nà Hills với Cầu Vàng tuyệt đẹp</li><li>Check-in tại khách sạn view biển Đà Nẵng</li></ul><h3>Ngày 1: <strong>Đà Nẵng - Huế</strong></h3><ul><li>Sáng (08:00): Đón khách tại Đà Nẵng, đi xe về Huế</li><li>Trưa (12:00): Ăn trưa tại Huế với bánh bèo, bánh lọc</li><li>Chiều (14:00): Tham quan Đại Nội, lăng tẩm Hoàng đế</li><li>Tối (18:00): Ăn tối, nghỉ đêm tại Huế</li></ul><h3>Ngày 2: <strong>Huế - Đà Nẵng</strong></h3><ul><li>Sáng (07:30): Tham quan chùa Thiên Mụ, đi đèo Hải Vân</li><li>Trưa (12:00): Ăn trưa tại Đà Nẵng</li><li>Chiều (14:00): Tham quan Bà Nà Hills, Cầu Vàng</li><li>Tối (19:00): Ăn tối, nghỉ đêm tại Đà Nẵng</li></ul><h3>Ngày 3: <strong>Đà Nẵng - Hội An</strong></h3><ul><li>Sáng (08:00): Đi biển Mỹ Khê, tham quan Ngũ Hành Sơn</li><li>Trưa (12:00): Ăn trưa với mì Quảng</li><li>Chiều (14:00): Đi Hội An, tham quan phố cổ</li><li>Tối (18:00): Ăn tối, ngắm đèn lồng Hội An, nghỉ đêm</li></ul><h3>Ngày 4: <strong>Hội An - Đà Nẵng</strong></h3><ul><li>Sáng (08:00): Mua sắm chợ phiên Hội An, tham quan thành cổ</li><li>Trưa (12:00): Ăn trưa, đi xe về Đà Nẵng</li><li>Chiều (15:00): Đưa khách ra sân bay, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đời mới đưa đón Đà Nẵng - Huế - Hội An</li><li>Khách sạn 3-4 sao (2 người/phòng)</li><li>Vé tham quan Đại Nội, Bà Nà Hills</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên tiếng Việt</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, đồ bơi</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm</li><li>Thời tiết miền Trung nóng, nên chuẩn bị nước uống đầy đủ</li><li>Tuân thủ quy định tại các di tích lịch sử</li><li>Giữ gìn vệ sinh môi trường tại các điểm đến</li></ul>', 'active', 5200000, 3800000, '["https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80"]', '2026-02-20 08:00:00'),
(7, 'Đà Lạt - Thành Phố Ngàn Hoa 4N3Đ', 'da-lat-thanh-pho-ngan-hoa', '<h3>Giới thiệu tour</h3><p>Tour khám phá Đà Lạt - thành phố ngàn hoa 4 ngày 3 đêm là chuyến đi thư giãn với khí hậu mát mẻ, cảnh đẹp thơ mộng và văn hóa độc đáo của cao nguyên Việt Nam.</p><h3>Điểm nổi bật</h3><ul><li>Thành phố ngàn hoa với vườn hoa Đà Lạt tuyệt đẹp</li><li>Khám phá thung lũng Tình Yêu với cảnh đẹp thơ mộng</li><li>Tham quan Dinh Bảo Đại - nơi ở của vị vua cuối cùng Việt Nam</li><li>Chinh phục đèo Pongour với thác nước tuyệt đẹp</li><li>Thưởng thức dâu tây Đà Lạt ngọt ngào</li><li>Check-in tại resort với không khí mát mẻ</li><li>Tham quan chợ đêm Đà Lạt sôi động</li></ul><h3>Ngày 1: <strong>TP.HCM - Đà Lạt</strong></h3><ul><li>Sáng (07:00): Đón khách, đi xe về Đà Lạt</li><li>Trưa (12:00): Ăn trưa trên đường hoặc tại thị xã</li><li>Chiều (15:00): Đến Đà Lạt, check-in khách sạn, nghỉ ngơi</li><li>Tối (18:00): Ăn tối, đi dạo chợ đêm, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Đà Lạt City Tour</strong></h3><ul><li>Sáng (08:00): Tham quan Dinh Bảo Đại, vườn hoa Đà Lạt</li><li>Trưa (12:00): Ăn trưa với đặc sản Đà Lạt</li><li>Chiều (14:00): Đi thung lũng Tình Yêu, thác Datanla</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Đà Lạt - Đèo Pongour</strong></h3><ul><li>Sáng (07:30): Đi đèo Pongour, tham quan thác Pongour</li><li>Trưa (12:00): Ăn trưa picnic</li><li>Chiều (14:00): Trở về Đà Lạt, nghỉ ngơi, mua sắm</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 4: <strong>Đà Lạt - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản Đà Lạt: dâu tây, mứt, rượu vang</li><li>Trưa (11:00): Ăn trưa, đi xe về TP.HCM</li><li>Chiều (16:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón TP.HCM - Đà Lạt - TP.HCM</li><li>Khách sạn 3-4 sao Đà Lạt (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp vì Đà Lạt mát mẻ</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm</li><li>Thời tiết Đà Lạt thay đổi thất thường, nên chuẩn bị áo ấm</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường thành phố ngàn hoa</li></ul>', 'active', 4800000, 3500000, '["https://images.unsplash.com/photo-1584172459597-619bb936a093?w=800&q=80","https://images.unsplash.com/photo-1586495981346-94c06fb90f91?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2026-02-25 14:00:00'),
(8, 'Hà Giang - Cao Nguyên Đá Đồng Văn 3N2Đ', 'ha-giang-cao-nguyen-da-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Hà Giang - cao nguyên đá Đồng Văn 3 ngày 2 đêm là hành trình chinh phục cung đường đèo đẹp nhất Việt Nam, khám phá văn hóa dân tộc độc đáo và cảnh đẹp tuyệt đẹp.</p><h3>Điểm nổi bật</h3><ul><li>Chinh phục đèo Mã Pí Lèng - đèo đẹp nhất Việt Nam</li><li>Ngắm hoa tam giác mạch mùa bông nở vàng rực rỡ</li><li>Cột cờ Lũng Cú - điểm cực Bắc của Tổ quốc</li><li>Khám phá văn hóa H''Mông, Dao, Tay độc đáo</li><li>Check-in tại nhà của vua đá - địa điểm nổi tiếng</li><li>Cung đường Quản Ba - Đồng Văn với cảnh đẹp hùng vĩ</li><li>Thưởng thức đặc sản Hà Giang: thịt trâu, mận Tam Đường</li></ul><h3>Ngày 1: <strong>Hà Nội - Hà Giang</strong></h3><ul><li>Sáng (06:00): Đón khách, đi xe về Hà Giang</li><li>Trưa (12:00): Ăn trưa tại Tuyên Quang với đặc sản địa phương</li><li>Chiều (16:00): Đến Hà Giang, check-in khách sạn, nghỉ ngơi</li><li>Tối (19:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Hà Giang - Đồng Văn - Mã Pí Lèng</strong></h3><ul><li>Sáng (07:00): Đi qua đèo Mã Pí Lèng, ngắm cảnh cao nguyên đá</li><li>Trưa (12:00): Ăn trưa tại Đồng Văn</li><li>Chiều (14:00): Tham quan Cột cờ Lũng Cú, nhà của vua đá</li><li>Tối (18:00): Nghỉ đêm tại Đồng Văn, ngắm đêm sao</li></ul><h3>Ngày 3: <strong>Đồng Văn - Hà Giang - Hà Nội</strong></h3><ul><li>Sáng (07:00): Mua sắm chợ phiên Đồng Văn, gặp gỡ người dân</li><li>Trưa (12:00): Ăn trưa, đi xe về Hà Nội</li><li>Chiều (18:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đời mới đưa đón Hà Nội - Hà Giang - Đồng Văn</li><li>Khách sạn 2-3 sao (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp vì Hà Giang rất lạnh về ban đêm</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm, máy ảnh</li><li>Đường đi có nhiều đèo dốc, nên chuẩn bị thuốc say xe</li><li>Tuân thủ phong tục tập quán của người dân địa phương</li><li>Giữ gìn vệ sinh môi trường cao nguyên đá</li></ul>', 'active', 3800000, 2800000, '["https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80"]', '2026-03-01 10:00:00'),
(9, 'Phú Quốc - Đảo Ngọc 3N2Đ', 'phu-quoc-dao-ngoc-3n2d', '<h3>Giới thiệu tour</h3><p>Tour nghỉ dưỡng Phú Quốc 3 ngày 2 đêm là kỳ nghỉ hoàn hảo tại đảo ngọc với những bãi biển tuyệt đẹp, resort cao cấp và đặc sản hải sản tươi ngon.</p><h3>Điểm nổi bật</h3><ul><li>Bãi Sao - bãi biển đẹp nhất Phú Quốc với nước biển xanh trong</li><li>Lặn ngắm san hô tại đảo Út - thủy cung tự nhiên</li><li>Câu cá đêm trên biển - trải nghiệm độc đáo</li><li>Tham quan nhà tù Phú Quốc - điểm lịch sử</li><li>Thưởng thức hải sản tươi sống: tôm hùm, ghẹ, cá</li><li>Check-in tại resort view biển 4-5 sao</li><li>Mua sắm đặc sản Phú Quốc: tiêu, mực, rượu sim</li></ul><h3>Ngày 1: <strong>TP.HCM - Phú Quốc</strong></h3><ul><li>Sáng (07:00): Đến sân bay Tân Sơn Nhất, bay đến Phú Quốc</li><li>Trưa (11:00): Đến Phú Quốc, nhận phòng resort, nghỉ ngơi</li><li>Chiều (14:00): Tham quan nhà tù Phú Quốc, đi bãi Sao</li><li>Tối (18:00): Ăn tối hải sản, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Phú Quốc - Đảo Út</strong></h3><ul><li>Sáng (07:30): Đi tàu ra đảo Út, lặn ngắm san hô</li><li>Trưa (12:00): Ăn trưa trên đảo với hải sản tươi</li><li>Chiều (14:00): Câu cá, bơi biển, trở về đất liền</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Phú Quốc - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản Phú Quốc: tiêu, mực, rượu sim</li><li>Trưa (11:00): Ăn trưa, ra sân bay bay về TP.HCM</li><li>Chiều (14:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé máy bay khứ hồi TP.HCM - Phú Quốc</li><li>Resort 4-5 sao Phú Quốc (2 người/phòng)</li><li>Vé tàu ra đảo Út</li><li>Vé tham quan nhà tù Phú Quốc</li><li>Thiết bị lặn ngắm san hô</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, áo bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết Phú Quốc nóng, nên chuẩn bị nước uống đầy đủ</li><li>Tuân thủ quy định an toàn khi lặn ngắm san hô</li><li>Giữ gìn vệ sinh môi trường đảo ngọc</li></ul>', 'active', 6800000, 4800000, '["https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-03-05 09:30:00'),
(10, 'Mũi Né - Phan Thiết 3N2Đ', 'mui-ne-phan-thiet-3n2d', '<h3>Giới thiệu tour</h3><p>Tour nghỉ dưỡng Mũi Né - Phan Thiết 3 ngày 2 đêm là lựa chọn hoàn hảo cho kỳ nghỉ cuối tuần với cảnh đẹp đồi cát, bãi biển yên bình và resort cao cấp.</p><h3>Điểm nổi bật</h3><ul><li>Đồi cát Mũi Né - cảnh đẹp独特 với đồi cát vàng và hồng</li><li>Bãi biển Mũi Né yên bình với nước biển xanh</li><li>Tham quan fishing village - làng chài truyền thống</li><li>Thưởng thức hải sản tươi ngon</li><li>Check-in tại resort view biển 4 sao</li><li>Hoạt động thể thao biển: lướt ván, kite surfing</li><li>Ngắm bình minh trên biển tuyệt đẹp</li></ul><h3>Ngày 1: <strong>TP.HCM - Phan Thiết</strong></h3><ul><li>Sáng (07:30): Đón khách, đi xe về Phan Thiết</li><li>Trưa (12:00): Ăn trưa tại nhà hàng đường biển</li><li>Chiều (14:00): Check-in resort, nghỉ ngơi, bơi biển</li><li>Tối (18:00): Ăn tối hải sản, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Mũi Né</strong></h3><ul><li>Sáng (05:30): Ngắm bình minh trên biển (nếu muốn)</li><li>Trưa (09:00): Tham quan đồi cát Mũi Né, chụp ảnh</li><li>Chiều (12:00): Ăn trưa, tham quan làng chài, bơi biển</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Phan Thiết - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản Phan Thiết: mực nướng, rượu nếp</li><li>Trưa (11:00): Ăn trưa, đi xe về TP.HCM</li><li>Chiều (15:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón TP.HCM - Phan Thiết - TP.HCM</li><li>Resort 4 sao Phan Thiết (2 người/phòng)</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li><li>Chi phí thuê thiết bị thể thao biển</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, áo bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết Mũi Né nóng, nên chuẩn bị nước uống đầy đủ</li><li>Tuân thủ quy định an toàn khi bơi biển</li><li>Giữ gìn vệ sinh môi trường bãi biển</li></ul>', 'active', 4200000, 3000000, '["https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80"]', '2026-03-10 14:00:00'),
(11, 'Hội An - Tour Ẩm Thực Đêm', 'hoi-an-am-thuc-dem', '<h3>Giới thiệu tour</h3><p>Tour ẩm thực đêm Hội An là hành trình khám phá nền ẩm thực đường phố nổi tiếng của phố cổ, thưởng thức các món ăn đặc sản và ngắm đèn lồng lung linh về buổi tối.</p><h3>Điểm nổi bật</h3><ul><li>Khám phá ẩm thực đường phố Hội An với nhiều món ăn ngon</li><li>Thưởng thức bánh mì Phượng - bánh mì nổi tiếng Hội An</li><li>Ngắm đèn lồng lung linh phố cổ Hội An về buổi tối</li><li>Thưởng thức cao lầu, mì Quảng, bánh xèo đặc sản</li><li>Tham quan các quán ăn cổ trong phố cổ</li><li>Học làm bánh xèo, bánh đúc với người dân địa phương</li><li>Uống trà sen và thưởng thức bánh trung thu Hội An</li></ul><h3>Ngày 1: <strong>Đà Nẵng - Hội An</strong></h3><ul><li>Chiều (16:00): Đón khách tại Đà Nẵng, đi xe về Hội An</li><li>Tối (17:30): Tham quan phố cổ, thưởng thức bánh mì Phượng</li><li>Tối (19:00): Ăn tối ẩm thực đường phố: cao lầu, mì Quảng</li><li>Tối (21:00): Ngắm đèn lồng, uống trà sen, về Đà Nẵng</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Đà Nẵng - Hội An</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên ẩm thực</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, mua sắm</li><li>Tiền tip cho hướng dẫn viên</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: máy ảnh để chụp ảnh đèn lồng</li><li>Tuân thủ quy định tại phố cổ Hội An</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 850000, 600000, '["https://images.unsplash.com/photo-1504214208698-ea1916a2195a?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80"]', '2026-03-15 11:00:00'),
(12, 'Ninh Bình - Tam Cốc - Tràng An 2N1Đ', 'ninh-binh-tam-coc-trang-an', '<h3>Giới thiệu tour</h3><p>Tour khám phá Ninh Bình 2 ngày 1 đêm là hành trình đến với "Vịnh Hạ Long trên cạn" với cảnh đẹp núi đá và sông nước tuyệt đẹp.</p><h3>Điểm nổi bật</h3><ul><li>Chùa Bái Đính - chùa lớn nhất Đông Nam Á với nhiều tượng Phật</li><li>Tràng An - di sản thế giới kép với cảnh đẹp tuyệt đẹp</li><li>Động Tam Cốc - Vịnh Hạ Long trên cạn với thung lũng núi đá</li><li>Tham quan đền vua Đinh Tiên Hoàng - vị vua đầu tiên thống nhất Việt Nam</li><li>Chèo thuyền tam bản khám phá sông nước</li><li>Check-in tại khách sạn với view núi đá</li><li>Thưởng thức đặc sản Ninh Bình: cá lăng, măng rừng</li></ul><h3>Ngày 1: <strong>Hà Nội - Ninh Bình</strong></h3><ul><li>Sáng (07:30): Đón khách, đi xe về Ninh Bình</li><li>Trưa (11:30): Ăn trưa với đặc sản Ninh Bình</li><li>Chiều (14:00): Tham quan chùa Bái Đính</li><li>Tối (18:00): Ăn tối, nghỉ đêm tại Ninh Bình</li></ul><h3>Ngày 2: <strong>Ninh Bình - Tam Cốc - Tràng An - Hà Nội</strong></h3><ul><li>Sáng (07:30): Đi Tràng An, chèo thuyền khám phá</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan động Tam Cốc, trở về Hà Nội</li><li>Tối (18:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Hà Nội - Ninh Bình - Hà Nội</li><li>Khách sạn 2-3 sao Ninh Bình (1 đêm, 2 người/phòng)</li><li>Vé tham quan chùa Bái Đính, Tràng An, Tam Cốc</li><li>Vé thuyền tam bản</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành, kính râm</li><li>Thời tiết Ninh Bình nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 1800000, 1300000, '["https://images.unsplash.com/photo-1586495981346-94c06fb90f91?w=800&q=80","https://images.unsplash.com/photo-1528127269322-539801943592?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80"]', '2026-03-20 09:00:00'),
(13, 'Mộc Châu - Trekking Hang Táu 2N1Đ', 'moc-chau-trekking-hang-tau', '<h3>Giới thiệu tour</h3><p>Tour trekking Mộc Châu và khám phá hang Táu 2 ngày 1 đêm là hành trình phiêu lưu khám phá thiên nhiên hoang sơ và văn hóa người Thái.</p><h3>Điểm nổi bật</h3><ul><li>Trekking tại hang Táu hoang sơ với cảnh đẹp tuyệt đẹp</li><li>Cắm trại giữa thiên nhiên với không khí trong lành</li><li>Khám phá văn hóa người Thái tại Mộc Châu</li><li>Thưởng thức chè Mộc Châu ngon ngọt</li><li>Check-in tại đồi chè với cảnh đẹp miệt vườn</li><li>Thưởng thức đặc sản Mộc Châu: thịt dê, chè</li><li>Trải nghiệm đời sống đồng ruộng của người dân</li></ul><h3>Ngày 1: <strong>Hà Nội - Mộc Châu</strong></h3><ul><li>Sáng (07:00): Đón khách, đi xe về Mộc Châu</li><li>Trưa (12:00): Ăn trưa với đặc sản Mộc Châu</li><li>Chiều (14:00): Trekking đến hang Táu, cắm trại</li><li>Tối (18:00): Ăn tối BBQ, ngủ lều</li></ul><h3>Ngày 2: <strong>Mộc Châu - Hà Nội</strong></h3><ul><li>Sáng (06:00): Tham quan đồi chè, thưởng thức chè Mộc Châu</li><li>Trưa (11:00): Ăn trưa, đi xe về Hà Nội</li><li>Chiều (16:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Hà Nội - Mộc Châu - Hà Nội</li><li>Lều trại, thiết bị cắm trại</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên trekking</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: thể thao, giày trekking tốt</li><li>Mang theo: kem chống nắng, mũ rộng vành, máy ảnh</li><li>Thời tiết Mộc Châu mát mẻ, nên chuẩn bị áo ấm</li><li>Tuân thủ hướng dẫn an toàn của HDV</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 2200000, 1600000, '["https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-03-25 13:00:00'),
(14, 'Quy Nhơn - Eo Gió 3N2Đ', 'quy-nhon-eo-gio-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Quy Nhơn 3 ngày 2 đêm là hành trình đến với những bãi biển yên bình và cảnh đẹp tuyệt đẹp tại miền Trung Việt Nam.</p><h3>Điểm nổi bật</h3><ul><li>Kỳ Co - bãi biển đẹp nhất Quy Nhơn với nước biển xanh trong</li><li>Eo Gió - Maldives của Việt Nam với cảnh đẹp tuyệt đẹp</li><li>Tháp Đôi Quy Nhơn - di tích lịch sử</li><li>Thưởng thức đặc sản bún chả cá Quy Nhơn</li><li>Check-in tại Hầm Hô với view biển đẹp</li><li>Tham quan Bảo tàng Quang Trung</li><li>Ngắm bình minh trên biển tuyệt đẹp</li></ul><h3>Ngày 1: <strong>TP.HCM - Quy Nhơn</strong></h3><ul><li>Sáng (07:00): Đến sân bay, bay đến Quy Nhơn</li><li>Trưa (11:00): Đến Quy Nhơn, nhận phòng khách sạn</li><li>Chiều (14:00): Đi Eo Gió, Kỳ Co</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Quy Nhơn City Tour</strong></h3><ul><li>Sáng (08:00): Tham quan Tháp Đôi, Bảo tàng Quang Trung</li><li>Trưa (12:00): Ăn trưa đặc sản bún chả cá</li><li>Chiều (14:00): Đi Hầm Hô, bãi biển</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Quy Nhơn - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản Quy Nhơn</li><li>Trưa (11:00): Ăn trưa, ra sân bay bay về TP.HCM</li><li>Chiều (14:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé máy bay khứ hồi TP.HCM - Quy Nhơn</li><li>Khách sạn 3-4 sao Quy Nhơn (2 người/phòng)</li><li>Vé tham quan các điểm du lịch</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm, máy ảnh</li><li>Thời tiết Quy Nhơn nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 3900000, 2800000, '["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80","https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80"]', '2026-03-30 10:00:00'),
(15, 'Vũng Tàu - Team Building 2N1Đ', 'vung-tau-team-building', '<h3>Giới thiệu tour</h3><p>Tour team building Vũng Tàu 2 ngày 1 đêm là chương trình gắn kết đội ngũ với các hoạt động vui chơi và thư giãn tại bãi biển.</p><h3>Điểm nổi bật</h3><ul><li>Chương trình team building chuyên nghiệp với các trò chơi</li><li>Games bãi biển sôi động và vui vẻ</li><li>Gala dinner đêm thứ 2 với chương trình biểu diễn</li><li>Tham quan tượng Chúa Kitô - biểu tượng Vũng Tàu</li><li>Check-in tại Bãi Trước với view biển đẹp</li><li>Thưởng thức hải sản tươi ngon</li><li>Hoạt động thể thao biển: bóng chuyền, bơi lội</li></ul><h3>Ngày 1: <strong>TP.HCM - Vũng Tàu</strong></h3><ul><li>Sáng (07:30): Đón khách, đi xe về Vũng Tàu</li><li>Trưa (11:30): Ăn trưa tại nhà hàng</li><li>Chiều (14:00): Team building games bãi biển</li><li>Tối (18:00): Gala dinner, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Vũng Tàu - TP.HCM</strong></h3><ul><li>Sáng (07:30): Tham quan tượng Chúa Kitô</li><li>Trưa (11:30): Ăn trưa, đi xe về TP.HCM</li><li>Chiều (15:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón TP.HCM - Vũng Tàu - TP.HCM</li><li>Khách sạn 3-4 sao Vũng Tàu (2 người/phòng)</li><li>Team building chuyên nghiệp</li><li>Bữa ăn theo chương trình</li><li>Gala dinner</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: thể thao, đồ bơi</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Vũng Tàu nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định an toàn trong các hoạt động</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 1500000, 1000000, '["https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-04-05 15:00:00'),
(16, 'Nha Trang - Tour Trăng Mật 4N3Đ', 'nha-trang-trang-mat-4n3d', '<h3>Giới thiệu tour</h3><p>Tour tuần trăng mật Nha Trang 4 ngày 3 đêm là chương trình romantic dành cho cặp đôi với resort cao cấp, bữa tối lãng mạn và các hoạt động thư giãn.</p><h3>Điểm nổi bật</h3><ul><li>Romantic package cho cặp đôi mới cưới</li><li>Bữa tối bãi biển lãng mạn với nến và hoa</li><li>Spa trị liệu cho 2 người tại resort</li><li>Resort view biển đẹp với phòng honeymoon</li><li>Hoa và nến trang trí phòng</li><li>Tour đảo, lặn ngắm san hô cùng nhau</li><li>Thưởng thức hải sản tươi ngon</li></ul><h3>Ngày 1: <strong>TP.HCM - Nha Trang</strong></h3><ul><li>Sáng (07:00): Đến sân bay, bay đến Nha Trang</li><li>Trưa (11:00): Đến Nha Trang, nhận phòng resort honeymoon</li><li>Chiều (14:00): Spa, massage trị liệu cho 2 người</li><li>Tối (18:00): Bữa tối lãng mạn, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Nha Trang</strong></h3><ul><li>Sáng (08:00): Bơi biển, thư giãn tại resort</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Spa, nghỉ ngơi</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Nha Trang - Tour Đảo</strong></h3><ul><li>Sáng (08:00): Tour đảo, lặn ngắm san hô</li><li>Trưa (12:00): Ăn trưa trên đảo</li><li>Chiều (14:00): Trở về, nghỉ ngơi</li><li>Tối (18:00): Bữa tối lãng mạn, nghỉ đêm</li></ul><h3>Ngày 4: <strong>Nha Trang - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm, ra sân bay bay về TP.HCM</li><li>Trưa (11:00): Ăn trưa</li><li>Chiều (14:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé máy bay khứ hồi TP.HCM - Nha Trang</li><li>Resort 5 sao (1 phòng cho 2 người)</li><li>Bữa ăn theo chương trình</li><li>Spa trị liệu</li><li>Hoa và nến trang trí</li><li>Tour đảo</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho nhân viên</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, đẹp cho bữa tối</li><li>Mang theo: kem chống nắng, máy ảnh</li><li>Thời tiết Nha Trang nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định của resort</li><li>Giữ gìn không gian lãng mạn</li></ul>', 'active', 8500000, 0, '["https://images.unsplash.com/photo-1544148103-0773bf10d330?w=800&q=80","https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1596895111956-bf1cf0599ce5?w=800&q=80"]', '2026-04-10 09:00:00'),
(17, 'Quảng Bình - Sông Chày - Hang Tối', 'quang-binh-song-chay-hang-toi', '<h3>Giới thiệu tour</h3><p>Tour khám phá Quảng Bình 2 ngày 1 đêm là hành trình khám phá hang động, zipline và các hoạt động mạo hiểm đầy thú vị.</p><h3>Điểm nổi bật</h3><ul><li>Zipline qua thung lũng sông Chày - trải nghiệm mạo hiểm</li><li>Bơi thuyền kayak trong hang động - khám phá Hang Tối</li><li>Khám phá Hang Tối hoang sơ chưa có đèn điện</li><li>Tham quan động Phong Nha - di sản thế giới</li><li>Trải nghiệm thiên nhiên hoang dã tại Vườn quốc gia</li><li>Check-in tại khách sạn với không khí yên bình</li><li>Thưởng thức đặc sản Quảng Bình</li></ul><h3>Ngày 1: <strong>Đồng Hới - Phong Nha</strong></h3><ul><li>Sáng (08:00): Đón khách, đi Phong Nha</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan động Phong Nha</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Phong Nha - Sông Chày</strong></h3><ul><li>Sáng (07:30): Đi sông Chày, zipline</li><li>Trưa (12:00): Ăn trưa picnic</li><li>Chiều (14:00): Bơi kayak, khám phá Hang Tối</li><li>Tối (17:00): Trở về Đồng Hới, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Đồng Hới - Phong Nha - Đồng Hới</li><li>Khách sạn 2-3 sao (1 đêm, 2 người/phòng)</li><li>Vé tham quan</li><li>Thiết bị zipline, kayak</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: thể thao, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Quảng Bình nóng, nên chuẩn bị nước uống</li><li>Tuân thủ hướng dẫn an toàn</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 2500000, 1800000, '["https://images.unsplash.com/photo-1533050487297-09b450131914?w=800&q=80","https://images.unsplash.com/photo-1583306346313-e9295d87f9eb?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-04-15 14:00:00'),
(18, 'Bình Thuận - Mũi Né Resort 3N2Đ', 'binh-thuan-mui-ne-resort', '<h3>Giới thiệu tour</h3><p>Tour nghỉ dưỡng Mũi Né 3 ngày 2 đêm là lựa chọn hoàn hảo cho kỳ nghỉ thư giãn với resort cao cấp và bãi biển yên bình.</p><h3>Điểm nổi bật</h3><ul><li>Resort 4 sao với hồ bơi riêng và view biển</li><li>Bãi biển Mũi Né đẹp với nước biển xanh</li><li>Tham quan đồi cát Mũi Né</li><li>Thưởng thức hải sản tươi ngon</li><li>Nghỉ dưỡng cho gia đình với các hoạt động</li><li>Spa và massage thư giãn</li><li>Ngắm bình minh trên biển tuyệt đẹp</li></ul><h3>Ngày 1: <strong>TP.HCM - Mũi Né</strong></h3><ul><li>Sáng (07:30): Đón khách, đi xe về Mũi Né</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Check-in resort, nghỉ ngơi</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Mũi Né</strong></h3><ul><li>Sáng (08:00): Đi biển, tham quan đồi cát</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Nghỉ ngơi tại resort, spa</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Mũi Né - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, đi xe về TP.HCM</li><li>Chiều (15:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón TP.HCM - Mũi Né - TP.HCM</li><li>Resort 4 sao (2 người/phòng)</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm</li><li>Thời tiết Mũi Né nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định của resort</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 4500000, 3200000, '["https://images.unsplash.com/photo-1559827260-dc66d52bef19?w=800&q=80","https://images.unsplash.com/photo-1566896022336-7702e477123d?w=800&q=80","https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80"]', '2026-04-20 11:00:00'),
(19, 'Đà Nẵng - Bà Nà Hills 3N2Đ', 'da-nang-ba-na-hills-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Đà Nẵng và Bà Nà Hills 3 ngày 2 đêm là hành trình đến với cầu vàng và làng Pháp trên đỉnh núi.</p><h3>Điểm nổi bật</h3><ul><li>Cầu Vàng - biểu tượng mới của Đà Nẵng với cảnh đẹp tuyệt đẹp</li><li>Làng Pháp trên đỉnh núi Bà Nà với kiến trúc cổ điển</li><li>Cáp treo dài nhất thế giới lên đỉnh Bà Nà</li><li>Tham quan Ngũ Hành Sơn - điểm tham quan nổi tiếng</li><li>Check-in tại biển Mỹ Khê với view biển đẹp</li><li>Thưởng thức đặc sản Mì Quảng</li><li>Ngắm đêm Đà Nẵng với cầu Rồng lung linh</li></ul><h3>Ngày 1: <strong>Đà Nẵng - Bà Nà</strong></h3><ul><li>Sáng (08:00): Đón khách tại Đà Nẵng</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Đi Bà Nà Hills, tham quan Cầu Vàng</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Đà Nẵng City Tour</strong></h3><ul><li>Sáng (08:00): Đi biển Mỹ Khê, tham quan Ngũ Hành Sơn</li><li>Trưa (12:00): Ăn trưa với Mì Quảng</li><li>Chiều (14:00): Tham quan Cầu Rồng, chợ Hàn</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Đà Nẵng</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa</li><li>Chiều (14:00): Kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé cáp treo Bà Nà Hills</li><li>Khách sạn 3-4 sao (2 người/phòng)</li><li>Vé tham quan Ngũ Hành Sơn</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp vì Bà Nà mát</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Đà Nẵng thay đổi, nên chuẩn bị áo ấm</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 4200000, 3000000, '["https://images.unsplash.com/photo-1558618666-fcd25c85cd64?w=800&q=80","https://images.unsplash.com/photo-1559592413-7cec4d0cae2b?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80"]', '2026-04-25 08:00:00'),
(20, 'Bắc Kạn - Ba Bể 3N2Đ', 'bac-kan-ba-be-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Ba Bể - Bắc Kạn 3 ngày 2 đêm là hành trình đến với hồ Ba Bể - hồ nước ngọt lớn nhất Việt Nam và cảnh đẹp núi rừng tuyệt đẹp.</p><h3>Điểm nổi bật</h3><ul><li>Hồ Ba Bể - hồ nước ngọt lớn nhất Việt Nam với cảnh đẹp tuyệt đẹp</li><li>Động Puông - hang động đẹp với nhũ đá kỳ ảo</li><li>Tham quan Bản Thái - văn hóa người Thái</li><li>Chèo thuyền khám phá hồ Ba Bể</li><li>Check-in tại homestay với người dân địa phương</li><li>Thưởng thức đặc sản Bắc Kạn: cá Ba Bể, măng rừng</li><li>Trải nghiệm cuộc sống đồng ruộng của người dân</li></ul><h3>Ngày 1: <strong>Hà Nội - Bắc Kạn</strong></h3><ul><li>Sáng (07:00): Đón khách, đi xe về Bắc Kạn</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (15:00): Đến Bắc Kạn, check-in homestay</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Bắc Kạn - Ba Bể</strong></h3><ul><li>Sáng (07:30): Đi hồ Ba Bể, chèo thuyền</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan động Puông, Bản Thái</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Bắc Kạn - Hà Nội</strong></h3><ul><li>Sáng (07:30): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, đi xe về Hà Nội</li><li>Chiều (16:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Hà Nội - Bắc Kạn - Hà Nội</li><li>Homestay (2 người/phòng)</li><li>Vé tham quan</li><li>Vé thuyền</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Bắc Kạn mát mẻ, nên chuẩn bị áo ấm</li><li>Tuân thủ phong tục tập quán của người dân</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 2800000, 2000000, '["https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-04-30 10:00:00'),
(21, 'Lào Cai - Bắc Hà 2N1Đ', 'lao-cai-bac-ha-2n1d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Bắc Hà - Lào Cai 2 ngày 1 đêm là hành trình khám phá văn hóa người H''Mông và cảnh đẹp cao nguyên Bắc Hà.</p><h3>Điểm nổi bật</h3><ul><li>Chợ phiên Bắc Hà - chợ phiên lớn nhất miền Bắc</li><li>Khám phá văn hóa người H''Mông độc đáo</li><li>Tham quan các bản làng người H''Mông</li><li>Check-in tại homestay với người dân địa phương</li><li>Thưởng thức đặc sản Lào Cai: thịt trâu, mận</li><li>Ngắm cảnh đẹp cao nguyên Bắc Hà</li><li>Trải nghiệm cuộc sống của người dân</li></ul><h3>Ngày 1: <strong>Lào Cai - Bắc Hà</strong></h3><ul><li>Sáng (07:00): Đón khách tại Lào Cai, đi xe về Bắc Hà</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan các bản làng</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Bắc Hà - Lào Cai</strong></h3><ul><li>Sáng (06:00): Tham quan chợ phiên Bắc Hà</li><li>Trưa (11:00): Ăn trưa, đi xe về Lào Cai</li><li>Chiều (14:00): Về đến Lào Cai, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Lào Cai - Bắc Hà - Lào Cai</li><li>Homestay (1 đêm, 2 người/phòng)</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp vì Bắc Hà rất lạnh</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Bắc Hà lạnh, nên chuẩn bị đủ áo ấm</li><li>Tuân thủ phong tục tập quán của người dân</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 1900000, 1400000, '["https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&q=80"]', '2026-05-01 09:00:00'),
(22, 'Cà Mau - Mũi Cà Mau 3N2Đ', 'ca-mau-mui-ca-mau-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Cà Mau - Mũi Cà Mau 3 ngày 2 đêm là hành trình đến với cực Nam của Việt Nam và văn hóa sông nước miền Tây.</p><h3>Điểm nổi bật</h3><ul><li>Mũi Cà Mau - cực Nam của Việt Nam</li><li>Tham quan Vườn quốc gia Mũi Cà Mau</li><li>Trải nghiệm sông nước miền Tây</li><li>Tham quan các khu bảo tồn thiên nhiên</li><li>Thưởng thức đặc sản Cà Mau: tôm, cua, cá</li><li>Check-in tại khách sạn với không khí yên bình</li><li>Ngắm cảnh đẹp rừng đước và sông nước</li></ul><h3>Ngày 1: <strong>TP.HCM - Cà Mau</strong></h3><ul><li>Sáng (07:00): Đến sân bay, bay đến Cà Mau</li><li>Trưa (11:00): Đến Cà Mau, nhận phòng</li><li>Chiều (14:00): Tham quan các điểm</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Cà Mau - Mũi Cà Mau</strong></h3><ul><li>Sáng (07:30): Đi Mũi Cà Mau, tham quan</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Khám phá vườn quốc gia</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Cà Mau - TP.HCM</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, ra sân bay bay về TP.HCM</li><li>Chiều (14:00): Về đến TP.HCM, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé máy bay khứ hồi TP.HCM - Cà Mau</li><li>Khách sạn 2-3 sao (2 người/phòng)</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Cà Mau nóng ẩm, nên chuẩn bị nước uống</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 3200000, 2300000, '["https://images.unsplash.com/photo-1597165309222-d5c746940c78?w=800&q=80","https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80"]', '2026-05-02 14:00:00'),
(23, 'Bình Định - Quy Nhơn 3N2Đ', 'binh-dinh-quy-nhon-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Quy Nhơn - Bình Định 3 ngày 2 đêm là hành trình đến với những bãi biển yên bình và di tích lịch sử.</p><h3>Điểm nổi bật</h3><ul><li>Bãi biển Ghenh Rang - bãi biển đẹp Quy Nhơn</li><li>Tháp Đôi - di tích lịch sử</li><li>Eo Gió - cảnh đẹp tuyệt đẹp</li><li>Thưởng thức đặc sản bún chả cá</li><li>Check-in tại khách sạn view biển</li><li>Tham quan Bảo tàng Quang Trung</li><li>Ngắm bình minh trên biển</li></ul><h3>Ngày 1: <strong>Đà Nẵng - Quy Nhơn</strong></h3><ul><li>Sáng (08:00): Đón khách, đi xe về Quy Nhơn</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan Tháp Đôi</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Quy Nhơn</strong></h3><ul><li>Sáng (08:00): Đi Eo Gió, Ghenh Rang</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan Bảo tàng Quang Trung</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Quy Nhơn - Đà Nẵng</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, đi xe về Đà Nẵng</li><li>Chiều (15:00): Về đến Đà Nẵng, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Đà Nẵng - Quy Nhơn - Đà Nẵng</li><li>Khách sạn 3-4 sao (2 người/phòng)</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: đồ bơi, kem chống nắng</li><li>Mang theo: mũ rộng vành, kính râm</li><li>Thời tiết Quy Nhơn nóng, nên chuẩn bị nước uống</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 3500000, 2500000, '["https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80","https://images.unsplash.com/photo-1590077428593-a55bb07c4665?w=800&q=80"]', '2026-05-03 10:00:00'),
(24, 'Kon Tum - Pleiku 3N2Đ', 'kon-tum-pleiku-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Kon Tum - Pleiku 3 ngày 2 đêm là hành trình khám phá văn hóa dân tộc Tây Nguyên và cảnh đẹp cao nguyên.</p><h3>Điểm nổi bật</h3><ul><li>Khám phá văn hóa dân tộc Tây Nguyên: Ba Na, Xo Dang</li><li>Tham quan nhà dài - kiến trúc độc đáo của người Tây Nguyên</li><li>Check-in tại homestay với người dân địa phương</li><li>Thưởng thức đặc sản Tây Nguyên: thịt lợn cắp nách, rượu cần</li><li>Tham quan các điểm tham quan lịch sử</li><li>Ngắm cảnh đẹp cao nguyên</li><li>Trải nghiệm cuộc sống của người dân</li></ul><h3>Ngày 1: <strong>Đà Nẵng - Kon Tum</strong></h3><ul><li>Sáng (07:00): Đón khách, đi xe về Kon Tum</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Tham quan các điểm</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Kon Tum - Pleiku</strong></h3><ul><li>Sáng (08:00): Đi Pleiku, tham quan</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Khám phá văn hóa dân tộc</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Pleiku - Đà Nẵng</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, đi xe về Đà Nẵng</li><li>Chiều (15:00): Về đến Đà Nẵng, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Xe đưa đón Đà Nẵng - Kon Tum - Pleiku - Đà Nẵng</li><li>Homestay và khách sạn (2 người/phòng)</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên địa phương</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: nhẹ nhàng, thoáng mát</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Tây Nguyên mát mẻ, nên chuẩn bị áo ấm</li><li>Tuân thủ phong tục tập quán của người dân</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 2800000, 2000000, '["https://images.unsplash.com/photo-1506905920300-13f10d3d4b3e?w=800&q=80","https://images.unsplash.com/photo-1583417319070-4a69db38a482?w=800&q=80"]', '2026-05-04 09:00:00'),
(25, 'Điện Biên - Mường Lay 3N2Đ', 'dien-bien-muang-lay-3n2d', '<h3>Giới thiệu tour</h3><p>Tour khám phá Điện Biên - Mường Lay 3 ngày 2 đêm là hành trình đến với chiến trường lịch sử và cảnh đẹp núi rừng.</p><h3>Điểm nổi bật</h3><ul><li>Tham quan chiến trường Điện Biên Phủ - điểm lịch sử</li><li>Khám phá Mường Lay - cảnh đẹp núi rừng</li><li>Check-in tại khách sạn với không khí yên bình</li><li>Thưởng thức đặc sản Điện Biên: thịt trâu, mận</li><li>Tham quan các di tích lịch sử</li><li>Ngắm cảnh đẹp núi rừng</li><li>Trải nghiệm cuộc sống của người dân địa phương</li></ul><h3>Ngày 1: <strong>Hà Nội - Điện Biên</strong></h3><ul><li>Sáng (07:00): Đến sân bay, bay đến Điện Biên</li><li>Trưa (11:00): Đến Điện Biên, nhận phòng</li><li>Chiều (14:00): Tham quan chiến trường</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 2: <strong>Điện Biên - Mường Lay</strong></h3><ul><li>Sáng (08:00): Đi Mường Lay, tham quan</li><li>Trưa (12:00): Ăn trưa</li><li>Chiều (14:00): Khám phá cảnh đẹp</li><li>Tối (18:00): Ăn tối, nghỉ đêm</li></ul><h3>Ngày 3: <strong>Điện Biên - Hà Nội</strong></h3><ul><li>Sáng (08:00): Mua sắm đặc sản</li><li>Trưa (11:00): Ăn trưa, ra sân bay bay về Hà Nội</li><li>Chiều (14:00): Về đến Hà Nội, kết thúc tour</li></ul><h3>Dịch vụ</h3><p><strong>Bao gồm</strong></p><ul><li>Vé máy bay khứ hồi Hà Nội - Điện Biên</li><li>Khách sạn 2-3 sao (2 người/phòng)</li><li>Vé tham quan</li><li>Bữa ăn theo chương trình</li><li>Hướng dẫn viên</li><li>Bảo hiểm du lịch</li></ul><p><strong>Không bao gồm</strong></p><ul><li>Chi phí cá nhân: đồ uống, giặt ủi, điện thoại</li><li>Tiền tip cho hướng dẫn viên và lái xe</li><li>Chi phí phụ thu phòng đơn</li><li>Các chi phí phát sinh ngoài chương trình</li></ul><h3>Lưu ý quan trọng</h3><ul><li>Mang theo giấy tờ tùy thân: CCCD/CMND/Hộ chiếu</li><li>Chuẩn bị trang phục: ấm áp vì Điện Biên lạnh</li><li>Mang theo: kem chống nắng, mũ rộng vành</li><li>Thời tiết Điện Biên lạnh, nên chuẩn bị đủ áo ấm</li><li>Tuân thủ quy định tại các điểm tham quan</li><li>Giữ gìn vệ sinh môi trường</li></ul>', 'active', 3200000, 2300000, '["https://images.unsplash.com/photo-1548266652-99cf27701ced?w=800&q=80","https://images.unsplash.com/photo-1532375810709-75b1da00537c?w=800&q=80"]', '2026-05-05 14:00:00');
